import { useEffect, useMemo, useState } from "react";
import api from "../api";

const PAGE_SIZE = 10;
const SYSTEM_ROLES = new Set(["ADMIN", "SALES", "ACCOUNTANT"]);
const isSystemName = (name) => SYSTEM_ROLES.has(String(name || "").toUpperCase());

function normalizePage(d) {
    if (Array.isArray(d)) return { list: d, pages: 1 };
    return { list: d?.content || [], pages: typeof d?.totalPages === "number" ? d.totalPages : 1 };
}
function useDebounce(value, delay = 400) {
    const [v, setV] = useState(value);
    useEffect(() => { const t = setTimeout(() => setV(value), delay); return () => clearTimeout(t); }, [value, delay]);
    return v;
}

export default function RoleEditor({ triggerLabel = "Vai trò & quyền" }) {
    const [open, setOpen] = useState(false);
    const [rows, setRows] = useState([]); const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1); const [loading, setLoading] = useState(false);

    const [q, setQ] = useState(""); const dq = useDebounce(q);
    const [active, setActive] = useState(""); const [permFilterIds, setPermFilterIds] = useState([]);

    const [perms, setPerms] = useState([]);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState(emptyForm());
    function emptyForm() { return { name: "", description: "", active: true, permissionIds: [] }; }

    useEffect(() => { if (open) loadPermissions(); }, [open]);
    useEffect(() => { if (open) loadRoles(); /* eslint-disable-next-line */ }, [open, page, dq, active, permFilterIds]);

    async function loadPermissions() {
        try {
            const { data } = await api.get("/api/roles/permissions");
            setPerms((data || []).map((p) => ({ id: p.id, code: p.code || p.name, description: p.description || "" })));
        } catch { setPerms([]); }
    }

    async function loadRoles() {
        setLoading(true);
        try {
            const params = { q: dq || undefined, active: active === "" ? undefined : active === "true", permissionIds: permFilterIds.length ? permFilterIds.join(",") : undefined, page, size: PAGE_SIZE, sort: "id,desc" };
            const { data } = await api.get("/api/roles", { params });
            const { list, pages } = normalizePage(data);
            setRows(list.map((r) => ({
                id: r.id, name: r.name, description: r.description, active: r.active,
                permissions: (r.permissions || []).map((p) => ({ id: p.id, code: p.code || p.name, description: p.description || "" })),
            })));
            setTotalPages(pages);
        } catch { setRows([]); setTotalPages(1); }
        finally { setLoading(false); }
    }

    function openCreate() { setEditing(null); setForm(emptyForm()); }
    function openEdit(row) {
        setEditing(row);
        setForm({ name: row.name || "", description: row.description || "", active: !!row.active, permissionIds: (row.permissions || []).map((p) => p.id) });
    }

    async function save(e) {
        e?.preventDefault?.();
        try {
            if (!editing) {
                if (!form.name?.trim()) return alert("Tên vai trò không được trống");
                if (isSystemName(form.name)) return alert("Tên này là vai trò hệ thống, không được tạo trùng.");
                const payload = { name: form.name.trim().toUpperCase(), description: form.description?.trim() || null, active: !!form.active, permissionIds: form.permissionIds || [] };
                await api.post("/api/roles", payload);
            } else {
                const payload = { description: form.description?.trim() ?? null, active: !!form.active, permissionIds: form.permissionIds || [] };
                await api.put(`/api/roles/${editing.id}`, payload);
            }
            await loadRoles(); alert(editing ? "Đã cập nhật vai trò" : "Đã tạo vai trò");
            setEditing(null); setForm(emptyForm());
        } catch (err) { alert(err?.response?.data?.message || err?.response?.data?.error || "Lưu vai trò thất bại"); }
    }

    async function remove(row) {
        if (isSystemName(row?.name)) return alert("Không thể xoá vai trò hệ thống.");
        if (!window.confirm(`Xoá vai trò ${row.name}?`)) return;
        try { await api.delete(`/api/roles/${row.id}`); if (rows.length === 1 && page > 0) setPage((p) => p - 1); else await loadRoles(); }
        catch (err) { alert(err?.response?.data?.message || err?.response?.data?.error || "Xoá vai trò thất bại"); }
    }

    const permMap = useMemo(() => { const m = new Map(); perms.forEach((p) => m.set(p.id, p)); return m; }, [perms]);
    function toggleFilterPerm(id) { setPermFilterIds((prev) => prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]); setPage(0); }
    function toggleFormPerm(id) { setForm((f) => ({ ...f, permissionIds: f.permissionIds.includes(id) ? f.permissionIds.filter((x) => x !== id) : [...f.permissionIds, id] })); }

    return (
        <>
            <button onClick={() => setOpen(true)} className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">{triggerLabel}</button>
            {!open ? null : (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-6xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">Quản lý vai trò & quyền</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setOpen(false)}>Đóng</button>
                        </div>

                        <div className="p-5 grid grid-cols-1 lg:grid-cols-3 gap-6">
                            <div className="lg:col-span-2 space-y-3">
                                <div className="flex flex-wrap items-end gap-2">
                                    <div className="flex flex-col">
                                        <label className="text-xs text-slate-500 mb-1">Tìm kiếm</label>
                                        <input className="w-72 px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" placeholder="Tên / Mô tả vai trò…" value={q} onChange={(e) => { setQ(e.target.value); setPage(0); }} />
                                    </div>
                                    <div className="flex flex-col">
                                        <label className="text-xs text-slate-500 mb-1">Trạng thái</label>
                                        <select className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" value={active} onChange={(e) => { setActive(e.target.value); setPage(0); }}>
                                            <option value="">Tất cả</option><option value="true">ACTIVE</option><option value="false">INACTIVE</option>
                                        </select>
                                    </div>
                                    <div className="flex-1" />
                                    <button onClick={openCreate} className="px-3 py-2 rounded-lg bg-emerald-600 text-white hover:bg-emerald-700">Thêm vai trò</button>
                                </div>

                                <div className="rounded-xl border border-indigo-100 p-3 bg-slate-50/40">
                                    <div className="text-xs text-slate-500 mb-2">Lọc theo quyền</div>
                                    <div className="flex flex-wrap gap-2 max-h-24 overflow-auto">
                                        {perms.length === 0 ? <span className="text-sm text-slate-500">—</span> : perms.map((p) => {
                                            const on = permFilterIds.includes(p.id);
                                            return (
                                                <button key={p.id} onClick={() => toggleFilterPerm(p.id)} className={"px-2 py-1 rounded-full text-xs border " + (on ? "bg-indigo-600 text-white border-indigo-600" : "bg-white text-slate-700 border-indigo-100")} title={p.description || p.code}>{p.code}</button>
                                            );
                                        })}
                                    </div>
                                </div>

                                <div className="bg-white rounded-xl border border-indigo-100 overflow-auto">
                                    <table className="min-w-full text-sm">
                                        <thead className="bg-indigo-50 text-slate-600"><tr><th className="px-4 py-3 text-left">Tên</th><th className="px-4 py-3 text-left">Mô tả</th><th className="px-4 py-3 text-left">Trạng thái</th><th className="px-4 py-3 text-left">Quyền</th><th className="px-4 py-3 text-right">Thao tác</th></tr></thead>
                                        <tbody className="divide-y">
                                        {loading ? (
                                            <tr><td className="px-4 py-5" colSpan={5}>Đang tải…</td></tr>
                                        ) : rows.length === 0 ? (
                                            <tr><td className="px-4 py-5" colSpan={5}>Chưa có dữ liệu</td></tr>
                                        ) : (
                                            rows.map((r) => {
                                                const sys = isSystemName(r.name);
                                                return (
                                                    <tr key={r.id} className="hover:bg-indigo-50/40">
                                                        <td className="px-4 py-3 font-medium">{r.name}</td>
                                                        <td className="px-4 py-3">{r.description || "-"}</td>
                                                        <td className="px-4 py-3">
                                                            <span className={"px-2 py-0.5 rounded-full text-xs " + (r.active ? "bg-emerald-100 text-emerald-700" : "bg-slate-100 text-slate-700")}>{r.active ? "ACTIVE" : "INACTIVE"}</span>
                                                        </td>
                                                        <td className="px-4 py-3">
                                                            <div className="flex flex-wrap gap-1">
                                                                {(r.permissions || []).slice(0, 6).map((p) => <span key={p.id} className="px-2 py-0.5 rounded-full bg-slate-100 text-slate-700 text-xs">{p.code}</span>)}
                                                                {(r.permissions || []).length > 6 && <span className="px-2 py-0.5 rounded-full bg-slate-100 text-slate-700 text-xs">+{(r.permissions || []).length - 6}</span>}
                                                            </div>
                                                        </td>
                                                        <td className="px-4 py-3 text-right">
                                                            <div className="inline-flex gap-2">
                                                                <button onClick={() => openEdit(r)} className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                                                {!sys && <button onClick={() => remove(r)} className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xoá</button>}
                                                            </div>
                                                        </td>
                                                    </tr>
                                                );
                                            })
                                        )}
                                        </tbody>
                                    </table>
                                </div>

                                <div className="flex gap-2">
                                    <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50" onClick={() => setPage((p) => Math.max(0, p - 1))} disabled={page <= 0}>← Trước</button>
                                    <div className="px-3 py-1.5 text-sm">Trang {page + 1}/{totalPages}</div>
                                    <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50" onClick={() => setPage((p) => p + 1)} disabled={page + 1 >= totalPages}>Sau →</button>
                                </div>
                            </div>

                            <div className="lg:col-span-1">
                                <div className="rounded-2xl border border-indigo-100 bg-white shadow p-4">
                                    <div className="font-semibold mb-3">{editing ? "Sửa vai trò" : "Thêm vai trò"}</div>
                                    <form onSubmit={save} className="space-y-3">
                                        {!editing && (
                                            <div>
                                                <label className="text-sm text-slate-600">Tên vai trò</label>
                                                <input value={form.name} onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))} className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" placeholder="VD: SALES" required />
                                            </div>
                                        )}
                                        <div>
                                            <label className="text-sm text-slate-600">Mô tả</label>
                                            <input value={form.description} onChange={(e) => setForm((f) => ({ ...f, description: e.target.value }))} className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" placeholder="Mô tả ngắn" />
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <input id="role-active" type="checkbox" checked={!!form.active} onChange={(e) => setForm((f) => ({ ...f, active: e.target.checked }))} disabled={editing && isSystemName(editing.name)} />
                                            <label htmlFor="role-active" className="text-sm text-slate-600 select-none">Kích hoạt</label>
                                        </div>
                                        <div>
                                            <div className="text-sm text-slate-600 mb-1">Quyền</div>
                                            <div className="h-48 overflow-auto rounded-lg border border-indigo-100 p-2">
                                                {perms.length === 0 ? <div className="text-sm text-slate-500 px-2">—</div> : perms.map((p) => {
                                                    const checked = form.permissionIds.includes(p.id);
                                                    return (
                                                        <label key={p.id} className="flex items-center gap-2 px-2 py-1 rounded hover:bg-indigo-50 cursor-pointer">
                                                            <input type="checkbox" checked={checked} onChange={() => toggleFormPerm(p.id)} />
                                                            <div>
                                                                <div className="text-xs font-medium">{p.code}</div>
                                                                <div className="text-[11px] text-slate-500">{p.description || ""}</div>
                                                            </div>
                                                        </label>
                                                    );
                                                })}
                                            </div>
                                        </div>
                                        <div className="flex justify-end gap-2 pt-2">
                                            <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200" onClick={() => { setEditing(null); setForm(emptyForm()); }}>Huỷ</button>
                                            <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">{editing ? "Lưu thay đổi" : "Tạo vai trò"}</button>
                                        </div>
                                    </form>
                                </div>
                            </div>
                        </div>

                    </div>
                </div>
            )}
        </>
    );
}
